const results = $input.first().json.results || [];
const question = $('Extraire mot-cle').item.json.question;

const drugs = results.slice(0, 5).map(r => ({
  brand:   r.openfda?.brand_name?.[0]   || 'Unknown',
  generic: r.openfda?.generic_name?.[0] || 'Unknown',
  use:     (r.indications_and_usage?.[0] || '').slice(0, 250),
  warn:    (r.warnings?.[0]             || '').slice(0, 150)
}));

return [{ json: { drugs, question } }];

