const raw = $input.first().json.text || '{}';

let parsed;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    conseil: raw.slice(0, 300),
    medicament_recommande: 'Voir conseil',
    posologie: 'Consultez un medecin',
    avertissement: 'Ne pas depasser la dose prescrite.'
  };
}

return [{ json: { success: true, data: parsed } }];
